import{_ as r,C as o,c as E,o as l,a3 as i,b as A,w as e,a as n,G as s,a4 as B}from"./chunks/framework.CTM16EAR.js";const f=JSON.parse('{"title":"第三阶段：估测任务","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pomodoro-technique/03-estimate-tasks.md","filePath":"guide/pomodoro-technique/03-estimate-tasks.md","lastUpdated":1778035726000}'),h={name:"guide/pomodoro-technique/03-estimate-tasks.md"};function u(d,a,p,c,m,g){const t=o("Mermaid");return l(),E("div",null,[a[1]||(a[1]=i('<h1 id="第三阶段-估测任务" tabindex="-1">第三阶段：估测任务 <a class="header-anchor" href="#第三阶段-估测任务" aria-label="Permalink to &quot;第三阶段：估测任务&quot;">​</a></h1><p><strong>目标</strong>：学会较准确地预测任务需要多少番茄。</p><blockquote><p>预估字段与分段规则以 <a href="./../reference/activity.html">活动清单</a>、<a href="./../reference/planner.html">任务计划</a> 为准。</p></blockquote><hr><h2 id="为什么预估重要" tabindex="-1">为什么预估重要 <a class="header-anchor" href="#为什么预估重要" aria-label="Permalink to &quot;为什么预估重要&quot;">​</a></h2><p>预估不是瞎猜，而是：</p><ul><li><strong>计划的基础</strong>：知道任务要多久，才能合理安排一天</li><li><strong>信心的来源</strong>：准确的预估带来完成任务的掌控感</li><li><strong>改进的依据</strong>：通过对比预估vs实际，发现认知偏差</li></ul><hr><h2 id="pomotention-的预估系统" tabindex="-1">Pomotention 的预估系统 <a class="header-anchor" href="#pomotention-的预估系统" aria-label="Permalink to &quot;Pomotention 的预估系统&quot;">​</a></h2><h3 id="两级预估机制" tabindex="-1">两级预估机制 <a class="header-anchor" href="#两级预估机制" aria-label="Permalink to &quot;两级预估机制&quot;">​</a></h3><h4 id="_1-活动清单-首次预估-预估番茄数" tabindex="-1">1. 活动清单：首次预估（预估番茄数） <a class="header-anchor" href="#_1-活动清单-首次预估-预估番茄数" aria-label="Permalink to &quot;1. 活动清单：首次预估（预估番茄数）&quot;">​</a></h4><p><strong>位置</strong>：活动清单的任务条目（见 <a href="./../reference/activity.html">活动清单</a>）</p><p><strong>用途</strong>：</p><ul><li>添加任务时的第一反应</li><li>长期任务的总体预估</li></ul><p><strong>填写建议</strong>：</p><ul><li>凭直觉，不要纠结</li><li>记录第一反应的预估</li><li>可以之后根据实际数据调整</li></ul><h4 id="_2-任务计划-分段预估-最多-3-段" tabindex="-1">2. 任务计划：分段预估（最多 3 段） <a class="header-anchor" href="#_2-任务计划-分段预估-最多-3-段" aria-label="Permalink to &quot;2. 任务计划：分段预估（最多 3 段）&quot;">​</a></h4><p><strong>位置</strong>：任务计划视图中的任务卡片（见 <a href="./../reference/planner.html">任务计划</a>）</p><p><strong>用途</strong>：</p><ul><li>细化今日要执行的任务</li><li>把大任务拆分为 1-3 个部分</li><li>每部分独立预估番茄数</li></ul><p><strong>操作</strong>：</p><ol><li>将任务从活动清单纳入任务计划（拖拽或等价操作，以界面为准）</li><li>点击任务卡片展开</li><li>在预估区域添加最多 3 段预估</li><li>每段填写预估番茄数</li></ol><p><strong>数据同步</strong>：</p><ul><li>活动清单与任务计划中的预估是同步的</li><li>修改一边，另一边自动更新</li><li>首次预估作为默认值，分段预估细化执行计划</li></ul><hr><h2 id="预估工作流程" tabindex="-1">预估工作流程 <a class="header-anchor" href="#预估工作流程" aria-label="Permalink to &quot;预估工作流程&quot;">​</a></h2>',26)),(l(),A(B,null,{default:e(()=>[s(t,{id:"mermaid-158",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20%E9%A6%96%E6%AC%A1%E9%A2%84%E4%BC%B0%5B%E6%B4%BB%E5%8A%A8%E6%B8%85%E5%8D%95%3A%20%E9%A6%96%E6%AC%A1%E9%A2%84%E4%BC%B0%5D%0A%20%20%20%20%20%20%20%20A%5B%E6%B7%BB%E5%8A%A0%E6%96%B0%E4%BB%BB%E5%8A%A1%5D%20--%3E%20B%5B%E5%A1%AB%E5%86%99%E9%A2%84%E4%BC%B0%E7%95%AA%E8%8C%84%E6%95%B0%5D%0A%20%20%20%20%20%20%20%20B%20--%3E%20C%5B%E5%87%AD%E7%9B%B4%E8%A7%89%E7%8C%9C%E6%B5%8B%5D%0A%20%20%20%20%20%20%20%20C%20--%3E%20D%5B%E4%B8%8D%E7%BA%A0%E7%BB%93%EF%BC%8C%E5%BF%AB%E9%80%9F%E5%86%B3%E5%AE%9A%5D%0A%20%20%20%20end%0A%20%20%20%20%0A%20%20%20%20subgraph%20%E6%89%A7%E8%A1%8C%E8%AE%A1%E5%88%92%5B%E4%BB%BB%E5%8A%A1%E8%AE%A1%E5%88%92%3A%20%E5%88%86%E6%AE%B5%E7%BB%86%E5%8C%96%5D%0A%20%20%20%20%20%20%20%20E%5B%E7%BA%B3%E5%85%A5%E4%BB%8A%E6%97%A5%E8%AE%A1%E5%88%92%5D%20--%3E%20F%5B%E6%8B%86%E5%88%86%E4%B8%BA1-3%E6%AE%B5%5D%0A%20%20%20%20%20%20%20%20F%20--%3E%20G%5B%E6%AE%B51%3A%20%E5%AD%90%E4%BB%BB%E5%8A%A1A%5D%0A%20%20%20%20%20%20%20%20F%20--%3E%20H%5B%E6%AE%B52%3A%20%E5%AD%90%E4%BB%BB%E5%8A%A1B%5D%0A%20%20%20%20%20%20%20%20F%20--%3E%20I%5B%E6%AE%B53%3A%20%E5%AD%90%E4%BB%BB%E5%8A%A1C%5D%0A%20%20%20%20end%0A%20%20%20%20%0A%20%20%20%20subgraph%20%E5%AF%B9%E6%AF%94%E5%AD%A6%E4%B9%A0%5B%E6%89%A7%E8%A1%8C%E4%B8%8E%E5%AF%B9%E6%AF%94%5D%0A%20%20%20%20%20%20%20%20J%5B%E5%BC%80%E5%A7%8B%E7%95%AA%E8%8C%84%E8%AE%A1%E6%97%B6%5D%20--%3E%20K%5B%E8%AE%B0%E5%BD%95%E5%AE%9E%E9%99%85%E7%94%A8%E6%97%B6%5D%0A%20%20%20%20%20%20%20%20K%20--%3E%20L%5B%E5%AF%B9%E6%AF%94%E9%A2%84%E4%BC%B0vs%E5%AE%9E%E9%99%85%5D%0A%20%20%20%20%20%20%20%20L%20--%3E%20M%7B%E5%B7%AE%E8%B7%9D%E5%A4%A7%3F%7D%0A%20%20%20%20%20%20%20%20M%20--%3E%7C%E6%98%AF%7C%20N%5B%E5%88%86%E6%9E%90%E5%8E%9F%E5%9B%A0%5D%0A%20%20%20%20%20%20%20%20M%20--%3E%7C%E5%90%A6%7C%20O%5B%E7%A7%AF%E7%B4%AF%E7%BB%8F%E9%AA%8C%5D%0A%20%20%20%20end%0A%20%20%20%20%0A%20%20%20%20N%20--%3E%20P%5B%E8%B0%83%E6%95%B4%E4%B8%8B%E6%AC%A1%E9%A2%84%E4%BC%B0%5D%0A%20%20%20%20O%20--%3E%20P%0A%20%20%20%20P%20--%3E%20Q%5B%E9%A2%84%E4%BC%B0%E8%B6%8A%E6%9D%A5%E8%B6%8A%E5%87%86%5D%0A%20%20%20%20%0A%20%20%20%20%E9%A6%96%E6%AC%A1%E9%A2%84%E4%BC%B0%20--%3E%20%E6%89%A7%E8%A1%8C%E8%AE%A1%E5%88%92%20--%3E%20%E5%AF%B9%E6%AF%94%E5%AD%A6%E4%B9%A0%0A"})]),fallback:e(()=>a[0]||(a[0]=[n(" Loading... ")])),_:1})),a[2]||(a[2]=i('<hr><h2 id="预估技巧" tabindex="-1">预估技巧 <a class="header-anchor" href="#预估技巧" aria-label="Permalink to &quot;预估技巧&quot;">​</a></h2><h3 id="_1-先猜再算" tabindex="-1">1. 先猜再算 <a class="header-anchor" href="#_1-先猜再算" aria-label="Permalink to &quot;1. 先猜再算&quot;">​</a></h3><p>不要先分析再预估，而是：</p><ul><li>第一反应写下一个数字</li><li>然后简单想想是否合理</li><li>不合理再调整</li></ul><h3 id="_2-从简单任务开始" tabindex="-1">2. 从简单任务开始 <a class="header-anchor" href="#_2-从简单任务开始" aria-label="Permalink to &quot;2. 从简单任务开始&quot;">​</a></h3><p>预估的准确度提升需要时间：</p><ul><li>先做你熟悉的重复性任务</li><li>这类任务的预估最容易准</li><li>积累信心后再预估复杂任务</li></ul><h3 id="_3-记录预估偏差" tabindex="-1">3. 记录预估偏差 <a class="header-anchor" href="#_3-记录预估偏差" aria-label="Permalink to &quot;3. 记录预估偏差&quot;">​</a></h3><p>在任务追踪中，系统会自动对比：</p><ul><li>预估番茄数</li><li>实际番茄数</li><li>偏差比例</li></ul><p><strong>常见偏差模式</strong>：</p><ul><li><strong>乐观偏差</strong>：总是预估太少（&quot;这个很快&quot;）</li><li><strong>悲观偏差</strong>：总是预估太多（&quot;保险起见&quot;）</li><li><strong>任务膨胀</strong>：做着做着发现任务变大了</li><li><strong>意外干扰</strong>：低估了打断的影响</li></ul><h3 id="_4-处理不确定任务" tabindex="-1">4. 处理不确定任务 <a class="header-anchor" href="#_4-处理不确定任务" aria-label="Permalink to &quot;4. 处理不确定任务&quot;">​</a></h3><p>对于完全不熟悉的任务：</p><ul><li>预估时标注&quot;不确定&quot;</li><li>先做一个&quot;探索番茄&quot;（只了解任务，不完成）</li><li>探索后再做正式预估</li></ul><hr><h2 id="预估vs实际对比" tabindex="-1">预估vs实际对比 <a class="header-anchor" href="#预估vs实际对比" aria-label="Permalink to &quot;预估vs实际对比&quot;">​</a></h2><h3 id="在数据趋势中查看" tabindex="-1">在数据趋势中查看 <a class="header-anchor" href="#在数据趋势中查看" aria-label="Permalink to &quot;在数据趋势中查看&quot;">​</a></h3><p>在 <a href="./../reference/chart.html">数据趋势</a> 与「仪表盘」等入口（见 <a href="./../reference/interface.html">软件界面</a>）可查看：</p><ul><li>预估准确度趋势图</li><li>不同类型任务的预估偏差</li><li>长期改进曲线</li></ul><h3 id="分析维度" tabindex="-1">分析维度 <a class="header-anchor" href="#分析维度" aria-label="Permalink to &quot;分析维度&quot;">​</a></h3><ol><li><p><strong>按任务类型</strong></p><ul><li>哪类任务预估最准？</li><li>哪类总是偏差很大？</li></ul></li><li><p><strong>按时间段</strong></p><ul><li>上午的预估准还是下午？</li><li>疲劳时预估是否更不准？</li></ul></li><li><p><strong>按复杂度</strong></p><ul><li>小任务（1-2番茄）预估是否更准？</li><li>大任务是否总是膨胀？</li></ul></li></ol><hr><h2 id="本阶段检查清单" tabindex="-1">本阶段检查清单 <a class="header-anchor" href="#本阶段检查清单" aria-label="Permalink to &quot;本阶段检查清单&quot;">​</a></h2><ul><li>[ ] 每个新任务都填写首次预估番茄数</li><li>[ ] 当日任务计划中的任务都进行分段细化（1-3段）</li><li>[ ] 执行后对比预估vs实际</li><li>[ ] 定期查看 <a href="./../reference/chart.html">数据趋势</a> 的预估准确度趋势</li><li>[ ] 根据偏差调整后续预估策略</li></ul><hr><h2 id="什么时候进入下一阶段" tabindex="-1">什么时候进入下一阶段 <a class="header-anchor" href="#什么时候进入下一阶段" aria-label="Permalink to &quot;什么时候进入下一阶段&quot;">​</a></h2><p>当你：</p><ul><li>对常规任务的预估准确度达到 80% 以上</li><li>能识别自己的预估偏差模式</li><li>学会了处理不确定任务的策略</li></ul><p>进入 <a href="./04-optimize-flow.html">04-optimize-flow.md</a>，学习如何优化工作流程。</p>',31))])}const _=r(h,[["render",u]]);export{f as __pageData,_ as default};
